updateIntimacy(delta: number): number {
    const current = this.getIntimacy()
    const newLevel = Math.max(0, current + delta)
    const stmt = this.db.prepare('UPDATE intimacy SET level = ? WHERE id = 1')
    stmt.run(newLevel)
    return newLevel
  }

async close(): Promise<void> {
    // LanceDB Connection doesn't have an explicit close method;
    // dropping the reference is sufficient. This method exists for
    // interface symmetry and future compatibility.
    this.db = null as unknown as lancedb.Connection
  }

